        if (!_multiModel || !id2 || _multiModel.tables[0]?.id === id2) return;
        _multiModel.joins = _multiModel.joins.filter((j) => j.leftTableId !== id2 && j.rightTableId !== id2);
        _multiModel.tables = _multiModel.tables.filter((t) => t.id !== id2);
